<span class="line"><span style="color:#ABB2BF;">		c.TaskMeta[reply.TaskNumber].</span><span style="color:#E06C75;">MachineId</span><span style="color:#ABB2BF;"> </span><span style="color:#E5C07B;">=</span><span style="color:#ABB2BF;"> args.MachineId</span></span>
